import {
  Component,
  Prop,
  State,
  Element,
  Watch,
  Event,
  Method,
  EventEmitter,
  h
} from '@stencil/core';
import {
  getHostAttributes,
  getSpreadableAttributes,
  setDefaultHostAttributes,
  setStyleAttribute
} from '@src/utils/kds-utils/attributes/attributeUtils';
import { registerAttributeObserver } from '@src/utils/kds-utils/registerObserver';


interface KdsLinkHostElement extends HTMLElement {
  nativeElement: HTMLElement;
}

/**
 * Links are used as navigational elements. Only use them to take the user to another part of the experience or to download resources.
 *
 * > **Note:** `<kds-link />` is a [primitive web component](primitives/) that accepts all props listed below and any attributes prefixed with `inner-`.
 * `inner-*` attributes are stripped of their `inner-` prefix and placed onto the native element.
 */
@Component({
  tag: 'kds-link',
  styleUrl: 'kds-link.css',
  shadow: false
})
export class KdsLink {
  @Element() hostEl: KdsLinkHostElement;

  /** Removes underline text decoration unless on hover. */
  @Prop() readonly implied?: boolean;

  /** Contains a URL or a URL fragment. */
  @Prop() readonly href?: string;

  /** Instructs browsers to download a URL.  */
  @Prop() readonly download?: any;

  /** Applies the text-primary-inverse class. */
  @Prop() readonly inverse: boolean;

  /** Indicates the human language of the linked resource. */
  @Prop() readonly hreflang?: string;

  /** Specifies the relationship of the target object to the link object. */
  @Prop() readonly rel?: string;

  /** Specifies where to display the linked URL. */
  @Prop() readonly target?: string;

  /** Sets the font-size. */
  @Prop() readonly size?: 'inherit' | 'l' | 'm' | 's' | 'xs' = 'inherit';
  private sizeOpts = ['inherit', 'l', 'm', 's', 'xs'];

  /** Sets a class to the rendered `<a>`. */
  @Prop() readonly linkClass?: string;

  @State() innerAttrs: any;
  private observer: MutationObserver;
  private nativeElement: HTMLElement;

  /**
   * Emits when the component has been loaded. Event's `detail` contains a reference to the inner a element.
   */
  @Event() ready: EventEmitter;

  @Watch('size')
  validateSize(newSize: string) {
    const isOneOfKinds = this.sizeOpts.includes(newSize);
    if (!isOneOfKinds)
      console.error(
        `size: invalid size ${newSize}. Must be one of: ${this.sizeOpts}`
      );
  }

  componentWillLoad() {
    this.validateSize(this.size);
    this.observer = registerAttributeObserver(this);
    this.innerAttrs = getHostAttributes(this.hostEl);
    setDefaultHostAttributes(this.hostEl);
  }

  componentDidLoad() {
    this.observer.observe(this.hostEl, { attributes: true });
    this.ready.emit(this.nativeElement);
    this.hostEl.nativeElement = this.nativeElement;
  }

  disconnectedCallback() {
    this.observer && this.observer.disconnect();
  }

  /**
   * Returns the native `<a>` element used under the hood.
   */
  @Method()
  getNativeElement(): Promise<HTMLElement> {
    return Promise.resolve(this.nativeElement!);
  }

  render() {
    const { implied, size, rel, download } = this;
    const classes = {
      'kds-Link': true,
      [`kds-Link--${size}`]: true,
      'kds-Link--implied': implied,
      'text-primary-inverse': this.inverse,
      [this.linkClass]: Boolean(this.linkClass)
    };

    const isExternal = rel && rel.includes('external');
    const isDownload = download !== undefined;

    return (
      <a
        {...getSpreadableAttributes(this.innerAttrs)}
        href={this.href}
        hrefLang={this.hreflang}
        class={classes}
        download={this.download}
        rel={this.rel}
        target={this.target}
        ref={(el: HTMLElement) => {
          this.nativeElement = el;
          setStyleAttribute(el, this.innerAttrs);
        }}
      >
        <slot />
        {isExternal && <kds-icon-external />}
        {isDownload && <kds-icon-download />}
      </a>
    );
  }
}
